tool.command:
exec 3>&1 4>&2;
exec > enzywizard.log 2>&1;

MSMS_EXE=\$(command -v msms || command -v msms.x86_64Linux2.2.6.1 || true);
if [ -n "\$MSMS_EXE" ]; then mkdir -p "\$HOME"; echo "set pyvol_msms_exe, \$MSMS_EXE" > "\$HOME/.pymolrc"; fi;

mkdir -p tmp; export TMPDIR="\$PWD/tmp"; export TEMP="\$TMPDIR"; export TMP="\$TMPDIR"; export QT_QPA_PLATFORM=offscreen; export LIBGL_ALWAYS_SOFTWARE=1; export PYOPENGL_PLATFORM=osmesa;
mkdir -p python_compat;
printf '%s\n' 'import sys, types, io' 'try:' '    import numpy as np' '    if not hasattr(np, "float_"): np.float_ = np.float64' 'except Exception: pass' 'm = types.ModuleType("rdkit.six")' 'm.StringIO = io.StringIO' 'sys.modules.setdefault("rdkit.six", m)' 'try:' '    import rdkit; setattr(rdkit, "six", m)' 'except Exception: pass' > python_compat/sitecustomize.py;
export PYTHONPATH="\$PWD/python_compat\${PYTHONPATH:+:\$PYTHONPATH}";
echo "MSMS_EXE=\${MSMS_EXE:-not found}" >&4; command -v pymol >&4 2>&4 || true; command -v mk_prepare_receptor.py >&4 2>&4 || true; command -v enzywizard-pocket >&4 2>&4 || true; python -c 'import importlib.util, os, sys, numpy as np; print("HOME=", os.environ.get("HOME")); print("QT_QPA_PLATFORM=", os.environ.get("QT_QPA_PLATFORM")); print("pymol module=", bool(importlib.util.find_spec("pymol"))); print("pyvol module=", bool(importlib.util.find_spec("pyvol"))); print("numpy float_ shim=", hasattr(np, "float_")); print("rdkit.six shim=", "rdkit.six" in sys.modules)' >&4 2>&4 || true;

#set $input_name = $input_path.element_identifier
ln -s '$input_path' '$input_name' &&
mkdir -p diag_pyvol &&
python -c 'import sys,pathlib; from Bio.PDB import MMCIFParser,PDBParser,PDBIO; p=pathlib.Path(sys.argv[1]); parser=MMCIFParser(QUIET=True) if p.suffix.lower() in [".cif",".mmcif"] else PDBParser(QUIET=True); s=parser.get_structure("diag", str(p)); io=PDBIO(); io.set_structure(s); io.save("diag_pyvol/input.pdb")' '$input_name' > diag_pyvol/convert.stdout 2> diag_pyvol/convert.stderr || true;
printf '[General]\nprot_file = %s\nmin_rad = %s\nmax_rad = %s\nconstrain_radii = True\n[Specification]\nmode = all\nmin_volume = %s\n[Partitioning]\nsubdivide = False\n[Output]\nproject_dir = %s\nprefix = diag\nlogger_stream_level = INFO\nlogger_file_level = DEBUG\n' "\$PWD/diag_pyvol/input.pdb" '$advanced.min_rad' '$advanced.max_rad' '$advanced.min_volume' "\$PWD/diag_pyvol" > diag_pyvol/pyvol.cfg;
pyvol diag_pyvol/pyvol.cfg > diag_pyvol/pyvol.stdout 2>&1 || true;
echo "---- direct pyvol diagnostic ----" >&4; [ -f diag_pyvol/convert.stderr ] && cat diag_pyvol/convert.stderr >&4; [ -f diag_pyvol/pyvol.stdout ] && tail -n 200 diag_pyvol/pyvol.stdout >&4;
enzywizard-pocket
-i '$input_name'
--min_rad '$advanced.min_rad'
--max_rad '$advanced.max_rad'
--min_volume '$advanced.min_volume'
-o ./
;
status=\$?;
echo "---- files in Galaxy job working directory ----" >&4;
find . -maxdepth 4 -type f | sort >&4;
if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi;
if ! find . -maxdepth 2 -type f -name 'pocket_report*.json' | grep -q .; then echo "No EnzyWizard Pocket output file was produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
